)

$ErrorActionPreference = 'Stop'
Set-StrictMode -Version Latest

$BuildRoot = $env:APPVEYOR_BUILD_FOLDER
if ([string]::IsNullOrWhiteSpace($BuildRoot)) {
    $BuildRoot = Split-Path -Parent $PSScriptRoot
}
Set-Location $BuildRoot

$TranscriptPath = Join-Path $BuildRoot 'APPVEYOR_EXP19_1_BUILD.log'
try { Start-Transcript -LiteralPath $TranscriptPath -Force | Out-Null } catch { }

function Invoke-CheckedProcess {
    param(
        [Parameter(Mandatory=$true)][string]$FilePath,
        [Parameter(Mandatory=$false)][string[]]$ArgumentList = @(),
        [Parameter(Mandatory=$false)][string]$WorkingDirectory = $null
    )
    if ($WorkingDirectory) { Push-Location $WorkingDirectory }
    try {
        & $FilePath @ArgumentList
        if ($LASTEXITCODE -ne 0) {
            throw "$FilePath failed with exit code $LASTEXITCODE"
        }
    }
    finally {
        if ($WorkingDirectory) { Pop-Location }
    }
}

function Import-Vs2022Environment {
    $vswhere = Join-Path ${env:ProgramFiles(x86)} 'Microsoft Visual Studio\Installer\vswhere.exe'
    if (-not (Test-Path -LiteralPath $vswhere)) {
        throw "vswhere.exe not found: $vswhere"
    }
    $vsPath = & $vswhere -latest -products * -requires Microsoft.VisualStudio.Component.VC.Tools.x86.x64 -property installationPath
    if ([string]::IsNullOrWhiteSpace($vsPath)) {
        throw 'Visual Studio 2022 C++ toolset was not found on the AppVeyor worker.'
    }
    $vcvars = Join-Path $vsPath 'VC\Auxiliary\Build\vcvars64.bat'
    if (-not (Test-Path -LiteralPath $vcvars)) {
        throw "vcvars64.bat not found: $vcvars"
    }
    $lines = cmd.exe /s /c "`"$vcvars`" >nul && set"
    if ($LASTEXITCODE -ne 0) {
        throw 'vcvars64.bat failed.'
    }
    foreach ($line in $lines) {
        $pair = $line -split '=', 2
        if ($pair.Count -eq 2) {
            [Environment]::SetEnvironmentVariable($pair[0], $pair[1], 'Process')
        }
    }
    Write-Host "Visual Studio environment loaded from: $vsPath"
    Write-Host "MSBuild: $((Get-Command msbuild.exe -ErrorAction Stop).Source)"
}

function Invoke-WorkflowStep {
    param(
        [Parameter(Mandatory=$true)][string]$Name,
        [Parameter(Mandatory=$true)][scriptblock]$Action,
        [Parameter(Mandatory=$false)][string]$WorkingDirectory = $null
    )
    Write-Host ''
    Write-Host ('=' * 78)
    Write-Host "APPVEYOR STEP: $Name"
    Write-Host ('=' * 78)
    if ($WorkingDirectory) { Push-Location $WorkingDirectory }
    try {
        & $Action
    }
    finally {
        if ($WorkingDirectory) { Pop-Location }
    }
}

Import-Vs2022Environment

$env:RUNNER_TEMP = Join-Path $BuildRoot 'runner-temp'
New-Item -ItemType Directory -Path $env:RUNNER_TEMP -Force | Out-Null

$work = Join-Path $BuildRoot 'work'
