    'clone', '--no-checkout', '--filter=blob:none',
    'https://github.com/jaha2002-stack/DarkWolf-Clean-Visible-Reference.git',
    $work
)
Invoke-CheckedProcess -FilePath 'git.exe' -ArgumentList @(
    '-C', $work, 'fetch', '--depth', '1', 'origin',
    '229cd5d93b4c24ba705c9821a871cccf31b34b96'
)
Invoke-CheckedProcess -FilePath 'git.exe' -ArgumentList @(
    '-C', $work, 'checkout', '--detach',
    '229cd5d93b4c24ba705c9821a871cccf31b34b96'
)
$actualCommit = (& git.exe -C $work rev-parse HEAD).Trim()
if ($actualCommit -ne '229cd5d93b4c24ba705c9821a871cccf31b34b96') {
    throw "Unexpected base commit: $actualCommit"
}
