Invoke-WorkflowStep -Name 'Materialize Game Dynamic Lights Experiment 19 payloads' -Action {
$ErrorActionPreference = 'Stop'

$payloads = @(
  [pscustomobject]@{ Path='work/patches/270-d3d12-game-dynamic-lights-bridge-exp19.patch'; Sha='0D6DE687348D36F4316D58DDB7846A4A56921DB76FDE1DBB84E3DFEE8C542171'; Data='' },
  [pscustomobject]@{ Path='work/main/game_dynamic_lights_exp19.cfg'; Sha='C2C5C9249D59E256FD91FCA45528F46F7FFCC03DBA2EF84AD8F00CE82249027E'; Data='' },
  [pscustomobject]@{ Path='work/RUN_GAME_DYNAMIC_LIGHTS_EXP19.bat'; Sha='8A1CF935D5660A8ECF5B33108F140F154938F2A630D1142945C8DCD43D6B65AF'; Data='' },
  [pscustomobject]@{ Path='work/GAME_DYNAMIC_LIGHTS_EXP19_RUN_AND_COLLECT.ps1'; Sha='A65659BA74258BA9985700D4F98AEE0866B83D3AA0841F4AE83F1301A43AD322'; Data='' },
  [pscustomobject]@{ Path='work/README_GAME_DYNAMIC_LIGHTS_EXP19.txt'; Sha='93C53A52AB2EE6C477752994A97C0016496E080B2C40DB745ABBC76BA07F9FE3'; Data='' }
)
foreach ($payload in $payloads) {
  $parent = Split-Path -Parent $payload.Path
  if ($parent) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }
  [IO.File]::WriteAllBytes($payload.Path, [Convert]::FromBase64String($payload.Data))
  $actual = (Get-FileHash -Algorithm SHA256 -LiteralPath $payload.Path).Hash
  if ($actual -ne $payload.Sha) { throw "Payload hash mismatch: $($payload.Path)" }
  Write-Host "Materialized: $($payload.Path)"
}

$tokens = $null
$errors = $null
[void][System.Management.Automation.Language.Parser]::ParseFile(
  (Resolve-Path 'work/GAME_DYNAMIC_LIGHTS_EXP19_RUN_AND_COLLECT.ps1'),
  [ref]$tokens,
  [ref]$errors)
if ($errors.Count -gt 0) {
  $errors | ForEach-Object { Write-Error $_.Message }
  throw 'Experiment 19 collector PowerShell syntax validation failed.'
}
Write-Host 'Experiment 19 collector PowerShell syntax: PASSED'

}

